"use client";

import { useEffect, useMemo, useState } from "react";
import { Line, LineChart, ResponsiveContainer, Tooltip, XAxis, YAxis } from "recharts";
import { Plus, Settings, LogOut, Pill, Clock, CheckCircle2, AlertTriangle } from "lucide-react";
import { defaultMedicines, getAdherenceData, type Medicine, type DoseStatus } from "@/lib/mock-data";

const STAT_CARD_STYLE = "glass-card p-4 md:p-5";

export default function DashboardPage() {
  const [medicines, setMedicines] = useState<Medicine[]>([]);
  const [range, setRange] = useState<"7" | "30">("7");
  const [menuOpen, setMenuOpen] = useState(false);

  useEffect(() => {
    const stored = window.localStorage.getItem("mediflow_meds");
    if (stored) {
      setMedicines(JSON.parse(stored));
      return;
    }
    window.localStorage.setItem("mediflow_meds", JSON.stringify(defaultMedicines));
    setMedicines(defaultMedicines);
  }, []);

  useEffect(() => {
    if (!medicines.length) return;
    window.localStorage.setItem("mediflow_meds", JSON.stringify(medicines));
  }, [medicines]);

  const adherenceData = useMemo(() => getAdherenceData(range), [range]);

  const stats = useMemo(() => {
    const total = medicines.reduce((acc, med) => acc + med.dailyDoses, 0);
    const taken = medicines.reduce(
      (acc, med) => acc + med.history.filter((dose) => dose.status === "taken").length,
      0
    );
    const missed = medicines.reduce(
      (acc, med) => acc + med.history.filter((dose) => dose.status === "missed").length,
      0
    );
    const adherenceRate = total ? Math.round((taken / total) * 100) : 0;
    return { total, taken, missed, adherenceRate };
  }, [medicines]);

  const todayList = useMemo(() => {
    return medicines.flatMap((med) =>
      med.schedule.map((time, index) => ({
        id: `${med.id}-${index}`,
        name: med.name,
        dosage: med.dosage,
        time,
        status: med.statuses[index] as DoseStatus,
        medId: med.id,
        scheduleIndex: index
      }))
    );
  }, [medicines]);

  const updateStatus = (medId: string, index: number, status: DoseStatus) => {
    setMedicines((prev) =>
      prev.map((med) => {
        if (med.id !== medId) return med;
        const nextStatuses = [...med.statuses];
        nextStatuses[index] = status;
        return { ...med, statuses: nextStatuses };
      })
    );
  };

  return (
    <div className="min-h-screen bg-mist">
      <header className="sticky top-0 z-40 border-b border-white/50 bg-white/80 backdrop-blur">
        <div className="section-shell flex items-center justify-between py-4">
          <div className="flex items-center gap-3">
            <span className="flex h-10 w-10 items-center justify-center rounded-2xl bg-ink text-white">MF</span>
            <div>
              <p className="text-sm font-semibold text-ink">MediFlow</p>
              <p className="text-xs text-subtle">Home Dashboard</p>
            </div>
          </div>
          <div className="flex items-center gap-3">
            <button className="rounded-full bg-ink px-4 py-2 text-sm font-semibold text-white shadow-soft">
              <span className="flex items-center gap-2">
                <Plus className="h-4 w-4" /> Add New Medicine
              </span>
            </button>
            <div className="relative">
              <button
                className="flex h-10 w-10 items-center justify-center rounded-full bg-white shadow-soft"
                onClick={() => setMenuOpen((prev) => !prev)}
                aria-label="User menu"
              >
                <span className="text-sm font-bold">JS</span>
              </button>
              {menuOpen && (
                <div className="absolute right-0 mt-3 w-40 rounded-xl border border-slate-200 bg-white p-2 shadow-soft">
                  <button className="flex w-full items-center gap-2 rounded-lg px-3 py-2 text-sm text-slate-700 hover:bg-slate-100">
                    <Settings className="h-4 w-4" /> Settings
                  </button>
                  <button className="flex w-full items-center gap-2 rounded-lg px-3 py-2 text-sm text-slate-700 hover:bg-slate-100">
                    <LogOut className="h-4 w-4" /> Logout
                  </button>
                </div>
              )}
            </div>
          </div>
        </div>
      </header>

      <main className="section-shell space-y-10 py-10">
        <section className="grid gap-4 md:grid-cols-4">
          <div className={STAT_CARD_STYLE}>
            <p className="text-xs uppercase tracking-wide text-subtle">Active Medicines</p>
            <p className="mt-3 text-3xl font-semibold text-ink">{medicines.length}</p>
          </div>
          <div className={STAT_CARD_STYLE}>
            <p className="text-xs uppercase tracking-wide text-subtle">Today Adherence</p>
            <p className="mt-3 text-3xl font-semibold text-ink">{stats.adherenceRate}%</p>
          </div>
          <div className={STAT_CARD_STYLE}>
            <p className="text-xs uppercase tracking-wide text-subtle">Streak</p>
            <p className="mt-3 text-3xl font-semibold text-ink">12 days</p>
          </div>
          <div className={STAT_CARD_STYLE}>
            <p className="text-xs uppercase tracking-wide text-subtle">Next Dose</p>
            <p className="mt-3 text-3xl font-semibold text-ink">2h 15m</p>
          </div>
        </section>

        <section className="grid gap-6 lg:grid-cols-[2fr,1fr]">
          <div className="glass-card p-6">
            <div className="flex flex-wrap items-center justify-between gap-4">
              <div>
                <h2 className="text-lg font-semibold text-ink">Adherence Overview</h2>
                <p className="text-sm text-subtle">Track doses taken across your chosen timeframe.</p>
              </div>
              <div className="flex items-center gap-2 rounded-full bg-slate-100 p-1">
                <button
                  className={`rounded-full px-3 py-1 text-sm ${range === "7" ? "bg-white shadow-soft" : "text-slate-500"}`}
                  onClick={() => setRange("7")}
                >
                  7 days
                </button>
                <button
                  className={`rounded-full px-3 py-1 text-sm ${range === "30" ? "bg-white shadow-soft" : "text-slate-500"}`}
                  onClick={() => setRange("30")}
                >
                  30 days
                </button>
              </div>
            </div>
            <div className="mt-6 h-64">
              <ResponsiveContainer width="100%" height="100%">
                <LineChart data={adherenceData}>
                  <XAxis dataKey="label" stroke="#94a3b8" fontSize={12} />
                  <YAxis domain={[0, 100]} stroke="#94a3b8" fontSize={12} />
                  <Tooltip contentStyle={{ borderRadius: 12, borderColor: "#e2e8f0" }} />
                  <Line type="monotone" dataKey="value" stroke="#3b82f6" strokeWidth={3} dot={{ r: 4 }} />
                </LineChart>
              </ResponsiveContainer>
            </div>
            <div className="mt-6 grid gap-3 sm:grid-cols-3">
              <div className="rounded-xl bg-slate-50 p-3">
                <p className="text-xs uppercase text-subtle">Total Doses</p>
                <p className="text-lg font-semibold text-ink">{stats.total}</p>
              </div>
              <div className="rounded-xl bg-slate-50 p-3">
                <p className="text-xs uppercase text-subtle">Taken</p>
                <p className="text-lg font-semibold text-ink">{stats.taken}</p>
              </div>
              <div className="rounded-xl bg-slate-50 p-3">
                <p className="text-xs uppercase text-subtle">Missed</p>
                <p className="text-lg font-semibold text-ink">{stats.missed}</p>
              </div>
            </div>
          </div>

          <div className="glass-card p-6">
            <h2 className="text-lg font-semibold text-ink">Upcoming Today</h2>
            <div className="mt-4 space-y-3">
              {todayList.map((dose) => (
                <div key={dose.id} className="rounded-xl border border-slate-100 bg-white p-4">
                  <div className="flex items-center justify-between">
                    <div>
                      <p className="font-semibold text-ink">{dose.name}</p>
                      <p className="text-sm text-subtle">{dose.dosage}</p>
                    </div>
                    <span className="text-xs text-slate-500">{dose.time}</span>
                  </div>
                  <div className="mt-3 flex items-center justify-between">
                    <span
                      className={`inline-flex items-center gap-1 rounded-full px-2 py-1 text-xs font-medium ${
                        dose.status === "taken"
                          ? "bg-green-50 text-green-700"
                          : dose.status === "missed"
                          ? "bg-rose-50 text-rose-700"
                          : "bg-blue-50 text-blue-700"
                      }`}
                    >
                      {dose.status === "taken" && <CheckCircle2 className="h-3 w-3" />}
                      {dose.status === "missed" && <AlertTriangle className="h-3 w-3" />}
                      {dose.status === "upcoming" && <Clock className="h-3 w-3" />}
                      {dose.status}
                    </span>
                    <button
                      className="rounded-full bg-ink px-3 py-1 text-xs font-semibold text-white"
                      onClick={() => updateStatus(dose.medId, dose.scheduleIndex, "taken")}
                    >
                      Mark as Taken
                    </button>
                  </div>
                </div>
              ))}
            </div>
          </div>
        </section>

        <section className="glass-card p-6">
          <div className="flex items-center justify-between">
            <h2 className="text-lg font-semibold text-ink">Active Medicines</h2>
            <button className="rounded-full border border-slate-200 px-3 py-1 text-xs text-slate-600">
              Grid view
            </button>
          </div>
          <div className="mt-5 grid gap-4 md:grid-cols-2 xl:grid-cols-3">
            {medicines.map((med) => (
              <div key={med.id} className="rounded-2xl border border-slate-100 bg-white p-5">
                <div className="flex items-center justify-between">
                  <div className="flex items-center gap-2">
                    <span className="flex h-9 w-9 items-center justify-center rounded-xl bg-blue-50 text-blue-600">
                      <Pill className="h-4 w-4" />
                    </span>
                    <div>
                      <p className="font-semibold text-ink">{med.name}</p>
                      <p className="text-xs text-subtle">{med.dosage}</p>
                    </div>
                  </div>
                  <div className="flex gap-2">
                    <button className="text-xs text-slate-500 hover:text-ink">Edit</button>
                    <button className="text-xs text-rose-500 hover:text-rose-600">Delete</button>
                  </div>
                </div>
                <div className="mt-4 rounded-xl bg-slate-50 p-3">
                  <p className="text-xs text-subtle">Schedule</p>
                  <p className="text-sm font-medium text-ink">{med.schedule.join(" � ")}</p>
                  <p className="mt-2 text-xs text-subtle">Next dose {med.nextDose}</p>
                </div>
              </div>
            ))}
          </div>
        </section>
      </main>
    </div>
  );
}
